export const COLLECTION_TEXT: Record<string, LocalizedCollectionText> = {
  "nordic-winters": { title: { en: "Best cars for Nordic winters", no: "Beste biler for nordiske vintre", de: "Die besten Autos für nordische Winter", sv: "De bästa bilarna för nordiska vintrar", fr: "Les meilleures voitures pour les hivers nordiques", pl: "Najlepsze auta na nordycką zimę", it: "Le migliori auto per gli inverni nordici", es: "Los mejores coches para los inviernos nórdicos" }, description: { en: "Composed on snow. Quiet on ice. Heated where it matters.", no: "Rolig på snø. Stille på is. Varm der det teller.", de: "Souverän auf Schnee. Leise auf Eis. Warm, wo es zählt.", sv: "Samlad på snö. Tyst på is. Varm där det behövs.", fr: "Posées sur la neige. Silencieuses sur la glace. Chauffées là où cela compte.", pl: "Spokojne na śniegu. Ciche na lodzie. Ogrzane tam, gdzie trzeba.", it: "Composte sulla neve. Silenziose sul ghiaccio. Calde dove serve.", es: "Serenos sobre nieve. Silenciosos sobre hielo. Calor donde importa." }, body: { en: "Winter does not care about marketing. These are the cars AutoVere returns to when the temperature drops and the road disappears under snow — composed, calm and comfortable when lesser cars become a chore.", no: "Vinteren bryr seg ikke om markedsføring. Dette er bilene AutoVere vender tilbake til når temperaturen faller og veien forsvinner under snø — rolige, kapable og komfortable når andre biler blir et slit.", de: "Der Winter interessiert sich nicht für Marketing. Zu diesen Autos kehrt AutoVere zurück, wenn die Temperaturen fallen und die Straße unter Schnee verschwindet — gelassen, souverän und komfortabel, wenn andere Autos zur Last werden.", sv: "Vintern bryr sig inte om marknadsföring. Det här är bilarna AutoVere återvänder till när temperaturen faller och vägen försvinner under snö — lugna, kompetenta och bekväma när andra bilar blir ett projekt.", fr: "L’hiver se moque du marketing. Ce sont les voitures vers lesquelles AutoVere revient quand la température tombe et que la route disparaît sous la neige — posées, compétentes et confortables quand d’autres deviennent une corvée.", pl: "Zima nie przejmuje się marketingiem. To auta, do których AutoVere wraca, gdy temperatura spada, a droga znika pod śniegiem — spokojne, kompetentne i komfortowe wtedy, gdy inne stają się uciążliwe.", it: "L’inverno non si cura del marketing. Sono le auto a cui AutoVere torna quando la temperatura scende e la strada scompare sotto la neve — composte, capaci e confortevoli quando altre diventano una fatica.", es: "El invierno no entiende de marketing. Son los coches a los que AutoVere vuelve cuando baja la temperatura y la carretera desaparece bajo la nieve: serenos, capaces y cómodos cuando otros empiezan a resultar agotadores." } },
  "quiet-luxury": { title: { en: "Quiet luxury EVs", no: "Stille luksus-elbiler", de: "Elektrische Vertreter des stillen Luxus", sv: "Tyst lyx bland elbilar", fr: "Les EV du luxe feutré", pl: "Elektryki cichego luksusu", it: "Le EV del lusso silenzioso", es: "Los eléctricos del lujo silencioso" }, description: { en: "Presence without announcement. Craft over chrome.", no: "Tilstedeværelse uten å rope. Håndverk foran krom.", de: "Präsenz ohne Lautstärke. Handwerk vor Chrom.", sv: "Närvaro utan att ropa. Hantverk före krom.", fr: "De la présence sans emphase. L’artisanat plutôt que le chrome.", pl: "Obecność bez hałasu. Rzemiosło ponad chromem.", it: "Presenza senza clamore. Più mestiere che cromo.", es: "Presencia sin exhibicionismo. Más oficio que cromo." }, body: { en: "Luxury used to shout. The new generation whispers. These EVs choose silence, restraint and material honesty over badge theatre, and reward you every time you settle into them.", no: "Luksus pleide å rope. Den nye generasjonen hvisker. Disse elbilene velger stillhet, tilbakeholdenhet og ærlige materialer fremfor merke-teater — og belønner deg hver gang du setter deg inn.", de: "Luxus hat früher laut gesprochen. Die neue Generation flüstert. Diese EVs setzen auf Ruhe, Zurückhaltung und ehrliche Materialien statt Marken-Theater — und belohnen Sie jedes Mal, wenn Sie einsteigen.", sv: "Lyx brukade skrika. Den nya generationen viskar. De här elbilarna väljer tystnad, återhållsamhet och materialärlighet framför emblemteater — och belönar dig varje gång du slår dig ned i dem.", fr: "Le luxe criait autrefois. La nouvelle génération murmure. Ces EV privilégient le silence, la retenue et l’honnêteté des matériaux plutôt que le théâtre du badge — et cela se ressent à chaque installation à bord.", pl: "Luksus kiedyś krzyczał. Nowe pokolenie mówi szeptem. Te elektryki stawiają na ciszę, powściągliwość i uczciwość materiałów zamiast gry logo — i odpłacają się tym za każdym razem, gdy do nich wsiadasz.", it: "Un tempo il lusso alzava la voce. La nuova generazione sussurra. Queste EV scelgono silenzio, sobrietà e materiali sinceri invece del teatro del badge — e ti ripagano ogni volta che sali a bordo.", es: "Antes el lujo gritaba. La nueva generación susurra. Estos eléctricos prefieren el silencio, la contención y la honestidad material al teatro del emblema, y te lo devuelven cada vez que te sientas dentro." } },
  "long-distance-comfort": { title: { en: "Built for long-distance comfort", no: "Bygget for langturkomfort", de: "Gebaut für Langstreckenkomfort", sv: "Byggda för långfärdskomfort", fr: "Pensées pour le grand confort sur longue distance", pl: "Stworzone do komfortu na długich trasach", it: "Pensate per il comfort sulle lunghe distanze", es: "Pensados para el confort en larga distancia" }, description: { en: "Six hours that should feel like one.", no: "Seks timer som burde føles som én.", de: "Sechs Stunden, die sich wie eine anfühlen sollten.", sv: "Sex timmar som borde kännas som en.", fr: "Six heures qui devraient en sembler une.", pl: "Sześć godzin, które powinny minąć jak jedna.", it: "Sei ore che dovrebbero sembrare una.", es: "Seis horas que deberían sentirse como una." }, body: { en: "Long drives expose every shortcut. Seats betray you by hour four, wind noise wears you down and poor damping starts to grate. These are the cars AutoVere trusts when the road is long and real life is even longer.", no: "Lange kjøreturer avslører alle snarveier. Setene svikter ved time fire, vindstøyen tærer og dårlig demping irriterer. Dette er bilene AutoVere stoler på når veien er lang og hverdagen enda lengre.", de: "Lange Fahrten entlarven jeden Kompromiss. Sitze verraten Sie in Stunde vier, Windgeräusche ermüden und schlechtes Dämpfen nervt. Das sind die Autos, denen AutoVere vertraut, wenn die Strecke lang ist und das echte Leben noch länger.", sv: "Långa körningar avslöjar varje genväg. Stolar sviker vid timme fyra, vindljud nöter och dålig dämpning börjar irritera. Det här är bilarna AutoVere litar på när vägen är lång och livet ännu längre.", fr: "Les longs trajets révèlent toutes les économies de bout de chandelle. Les sièges trahissent vers la quatrième heure, le bruit d’air fatigue et une suspension médiocre finit par lasser. Voilà les voitures auxquelles AutoVere fait confiance quand la route s’étire.", pl: "Długie trasy obnażają każdy skrót. Fotele poddają się w czwartej godzinie, szum wiatru męczy, a słabe tłumienie zaczyna drażnić. To auta, którym AutoVere ufa wtedy, gdy droga jest długa, a życie jeszcze dłuższe.", it: "I viaggi lunghi smascherano ogni scorciatoia. I sedili tradiscono alla quarta ora, il rumore del vento stanca e un assetto poco raffinato finisce per pesare. Sono le auto di cui AutoVere si fida quando la strada si allunga davvero.", es: "Los viajes largos delatan cualquier atajo. Los asientos te fallan en la cuarta hora, el ruido aerodinámico te agota y una suspensión mediocre termina por cansarte. Estos son los coches en los que AutoVere confía cuando la ruta se alarga de verdad." } },
  "underestimated": { title: { en: "Cars people underestimated", no: "Biler folk undervurderte", de: "Autos, die viele unterschätzt haben", sv: "Bilar som folk underskattade", fr: "Les voitures que l’on a sous-estimées", pl: "Auta, które ludzie niedocenili", it: "Auto sottovalutate", es: "Coches que mucha gente subestimó" }, description: { en: "Outside the spotlight. Inside, more thought than you would expect.", no: "Utenfor rampelyset. På innsiden, mer tanke enn du tror.", de: "Abseits des Rampenlichts. Innen steckt mehr Sorgfalt, als man erwartet.", sv: "Utanför strålkastarna. Inuti, mer eftertanke än du tror.", fr: "Hors des projecteurs. À bord, plus d’intelligence qu’on ne l’imagine.", pl: "Poza światłem reflektorów. W środku więcej przemyślenia, niż się wydaje.", it: "Lontane dai riflettori. Dentro, più sostanza di quanto sembri.", es: "Fuera del foco. Por dentro, más reflexión de la que imaginas." }, body: { en: "Not every great car arrives with a giant marketing budget. These are the ones owners tend to appreciate more after a year than on day one — quietly excellent and often the wiser answer.", no: "Ikke alle gode biler kommer med gigantisk markedsbudsjett. Dette er bilene eiere ofte liker bedre etter ett år enn på første dag — stille sterke og ofte det klokere valget.", de: "Nicht jedes gute Auto kommt mit einem riesigen Marketingbudget. Diese Modelle schätzen ihre Besitzer nach einem Jahr oft mehr als am ersten Tag — leise exzellent und häufig die klügere Antwort.", sv: "Inte varje bra bil kommer med en enorm marknadsbudget. Det här är modellerna som ägarna ofta uppskattar mer efter ett år än första dagen — stillsamt starka och ofta det klokare svaret.", fr: "Toutes les grandes voitures n’arrivent pas avec un budget marketing colossal. Celles-ci ont tendance à être davantage aimées après un an qu’au premier jour — discrètement excellentes et souvent plus intelligentes qu’elles n’en ont l’air.", pl: "Nie każde świetne auto przychodzi z ogromnym budżetem marketingowym. To te modele, które właściciele po roku lubią bardziej niż w dniu zakupu — cicho znakomite i często po prostu rozsądniejsze.", it: "Non tutte le grandi auto arrivano con un enorme budget marketing. Queste tendono a farsi apprezzare di più dopo un anno che al primo giorno — silenziosamente eccellenti e spesso più intelligenti di quanto sembri.", es: "No todos los grandes coches llegan con un presupuesto de marketing descomunal. Estos son los que suelen gustar más al cabo de un año que el primer día: discretamente brillantes y, a menudo, la respuesta más inteligente." } },
  "best-family-evs": { title: { en: "Best family EVs", no: "Beste familie-elbiler", de: "Die besten Familien-EVs", sv: "Bästa familje-elbilarna", fr: "Les meilleurs EV familiaux", pl: "Najlepsze rodzinne elektryki", it: "Le migliori EV per la famiglia", es: "Los mejores eléctricos familiares" }, description: { en: "Space, safety and calm — without compromise.", no: "Plass, trygghet og ro — uten kompromiss.", de: "Raum, Sicherheit und Gelassenheit — ohne Kompromisse.", sv: "Utrymme, trygghet och lugn — utan kompromiss.", fr: "De l’espace, de la sécurité et du calme — sans compromis.", pl: "Przestrzeń, bezpieczeństwo i spokój — bez kompromisów.", it: "Spazio, sicurezza e calma — senza compromessi.", es: "Espacio, seguridad y calma, sin concesiones." }, body: { en: "A family car is a quiet contract: space, safety, reliability and a cabin that can survive years of real life. These EVs deliver the fundamentals without forgetting that a good family car should still feel good to drive.", no: "En familiebil er en stille kontrakt: plass, trygghet, pålitelighet og en kupé som tåler år med ekte hverdagsliv. Disse elbilene leverer grunnjobben uten å glemme at en god familiebil fortsatt bør føles bra å kjøre.", de: "Ein Familienauto ist ein stiller Vertrag: Raum, Sicherheit, Verlässlichkeit und ein Innenraum, der Jahre echten Lebens aushält. Diese EVs liefern die Grundlagen, ohne zu vergessen, dass sich ein gutes Familienauto auch gut fahren sollte.", sv: "En familjebil är ett tyst kontrakt: utrymme, säkerhet, pålitlighet och en kupé som står pall för flera år av verkligt familjeliv. De här elbilarna levererar grunderna utan att glömma att en bra familjebil fortfarande ska kännas bra att köra.", fr: "Une voiture familiale est un contrat silencieux: de l’espace, de la sécurité, de la fiabilité et un habitacle capable d’encaisser des années de vraie vie. Ces EV assurent les fondamentaux sans oublier qu’une bonne familiale doit aussi rester agréable à conduire.", pl: "Samochód rodzinny to cichy kontrakt: przestrzeń, bezpieczeństwo, niezawodność i wnętrze, które wytrzyma lata prawdziwego życia. Te elektryki dowożą fundamenty, nie zapominając, że dobre rodzinne auto nadal powinno dobrze się prowadzić.", it: "Un’auto di famiglia è un patto silenzioso: spazio, sicurezza, affidabilità e un abitacolo capace di sopportare anni di vita vera. Queste EV centrano i fondamentali senza dimenticare che una buona familiare deve restare piacevole da guidare.", es: "Un coche familiar es un contrato silencioso: espacio, seguridad, fiabilidad y un habitáculo capaz de soportar años de vida real. Estos eléctricos cumplen en lo esencial sin olvidar que un buen coche familiar también debe dar gusto conducirlo." } },
  "city-life": { title: { en: "Cars built for city life", no: "Biler bygget for byliv", de: "Autos fürs Stadtleben", sv: "Bilar byggda för stadsliv", fr: "Des voitures pensées pour la ville", pl: "Auta stworzone do miasta", it: "Auto pensate per la vita urbana", es: "Coches pensados para la vida en ciudad" }, description: { en: "Composed in traffic. Confident in tight streets.", no: "Rolig i trafikken. Trygg i trange gater.", de: "Gelassen im Verkehr. Sicher in engen Straßen.", sv: "Lugn i trafiken. Trygg i trånga gator.", fr: "Posées dans le trafic. Sereines dans les rues étroites.", pl: "Spokojne w korku. Pewne w ciasnych ulicach.", it: "Composte nel traffico. Sicure nelle strade strette.", es: "Serenos en el tráfico. Seguros en calles estrechas." }, body: { en: "Cities punish bad packaging. Visibility, footprint, low-speed refinement and parking ease matter more here than headline figures. These are the urban companions AutoVere trusts most.", no: "Byen straffer dårlig pakking. Sikt, fotavtrykk, lavfartsraffinement og enkel parkering betyr mer her enn overskriftsdata. Dette er de urbane følgesvennene AutoVere stoler mest på.", de: "Städte bestrafen schlechtes Packaging. Übersicht, Außenmaß, Feinkultur im Langsamverkehr und leichtes Parken zählen hier mehr als Schlagzeilenwerte. Das sind die urbanen Begleiter, denen AutoVere am meisten vertraut.", sv: "Städer straffar dålig paketering. Sikt, yttermått, lågfarfinskänsla och enkel parkering betyder mer här än rubriksiffror. Det här är AutoVeres mest pålitliga stadskompisar.", fr: "La ville sanctionne les mauvaises proportions. La visibilité, l’encombrement, l’agrément à basse vitesse et la facilité de stationnement comptent ici davantage que les chiffres d’affiche. Voici les compagnons urbains qu’AutoVere préfère.", pl: "Miasto bezlitośnie obnaża złe proporcje. Widoczność, gabaryt, kultura jazdy przy niskich prędkościach i łatwość parkowania liczą się tu bardziej niż liczby z nagłówków. To właśnie tym miejskim towarzyszom AutoVere ufa najbardziej.", it: "La città punisce i cattivi ingombri. Visibilità, dimensioni, raffinatezza a bassa velocità e facilità di parcheggio contano più dei numeri da copertina. Sono questi i compagni urbani di cui AutoVere si fida di più.", es: "La ciudad castiga los malos planteamientos. Visibilidad, tamaño exterior, refinamiento a baja velocidad y facilidad para aparcar importan más aquí que las cifras de titular. Estos son los compañeros urbanos en los que más confía AutoVere." } },
  "lowest-ownership-stress": { title: { en: "Lowest ownership stress", no: "Lavest eierskapsstress", de: "Am wenigsten Besitzstress", sv: "Lägst ägarstress", fr: "Le moins de stress à l’usage", pl: "Najmniej stresu przy posiadaniu", it: "Minimo stress di possesso", es: "El menor estrés de propiedad" }, description: { en: "Cars owners stop thinking about — in the best way.", no: "Biler eiere slutter å tenke på — på den beste måten.", de: "Autos, an die Besitzer im besten Sinn aufhören zu denken.", sv: "Bilar som ägare slutar tänka på — på bästa sätt.", fr: "Des voitures auxquelles on cesse de penser — dans le bon sens du terme.", pl: "Auta, o których właściciele przestają myśleć — w najlepszym sensie.", it: "Auto a cui smetti di pensare — nel senso migliore possibile.", es: "Coches en los que dejas de pensar, en el mejor sentido." }, body: { en: "The best ownership experience is the one you forget you are having. These cars combine dependable software, predictable service and interiors that wear their years with grace.", no: "Den beste eieropplevelsen er den du glemmer at du har. Disse bilene kombinerer pålitelig programvare, forutsigbar service og interiører som eldes pent.", de: "Die beste Besitz-Erfahrung ist die, die man vergisst. Diese Autos verbinden verlässliche Software, planbaren Service und Innenräume, die würdevoll altern.", sv: "Den bästa ägarupplevelsen är den du glömmer att du har. De här bilarna kombinerar pålitlig mjukvara, förutsägbar service och interiörer som åldras väl.", fr: "La meilleure expérience de possession est celle que l’on oublie presque. Ces voitures conjuguent logiciel fiable, entretien prévisible et intérieurs qui vieillissent avec dignité.", pl: "Najlepsze doświadczenie posiadania to takie, o którym nie musisz pamiętać. Te auta łączą stabilne oprogramowanie, przewidywalny serwis i wnętrza, które starzeją się z klasą.", it: "La miglior esperienza di possesso è quella che quasi dimentichi di avere. Queste auto combinano software affidabile, assistenza prevedibile e interni che invecchiano con grazia.", es: "La mejor experiencia de propiedad es la que casi olvidas que estás viviendo. Estos coches combinan software fiable, servicio previsible e interiores que envejecen con dignidad." } },
  "reviewers-unexpectedly-loved": { title: { en: "Cars reviewers unexpectedly loved", no: "Biler anmelderne uventet elsket", de: "Autos, die Tester unerwartet mochten", sv: "Bilar som testare oväntat föll för", fr: "Les voitures que les essayeurs ont aimées à la surprise générale", pl: "Auta, które recenzenci niespodziewanie polubili", it: "Auto che i tester hanno amato più del previsto", es: "Coches que los probadores acabaron adorando" }, description: { en: "Quiet surprises that earned respect.", no: "Stille overraskelser som fortjente respekt.", de: "Leise Überraschungen, die sich Respekt verdient haben.", sv: "Tysta överraskningar som förtjänade respekt.", fr: "Des surprises feutrées qui ont gagné le respect.", pl: "Ciche niespodzianki, które zapracowały na szacunek.", it: "Sorprese silenziose che si sono guadagnate rispetto.", es: "Sorpresas discretas que se ganaron el respeto." }, body: { en: "Some cars arrive with low expectations and leave with quiet admiration. These are the ones reviewers kept coming back to — not for headlines, but for how they behave when the cameras stop rolling.", no: "Noen biler møter lave forventninger og drar med stille beundring. Dette er bilene anmelderne stadig kom tilbake til — ikke for overskriftene, men for hvordan de oppfører seg når kameraene er slått av.", de: "Manche Autos kommen mit niedrigen Erwartungen und gehen mit stiller Bewunderung. Das sind die Modelle, zu denen Tester immer wieder zurückkehrten — nicht wegen der Schlagzeilen, sondern wegen ihres Charakters abseits der Kamera.", sv: "Vissa bilar kommer in med låga förväntningar och går ut med stilla beundran. Det här är modellerna testarna återvände till — inte för rubrikerna, utan för hur de beter sig när kamerorna stängs av.", fr: "Certaines voitures arrivent avec peu d’attentes et repartent avec une admiration discrète. Ce sont celles vers lesquelles les essayeurs sont revenus — non pour les titres, mais pour leur comportement une fois les caméras coupées.", pl: "Niektóre auta wchodzą do testu z niskimi oczekiwaniami, a wychodzą z cichym podziwem. To te modele, do których recenzenci wracali nie dla nagłówków, lecz dla tego, jak zachowują się poza kamerą.", it: "Alcune auto arrivano con aspettative basse e se ne vanno con un’ammirazione silenziosa. Sono quelle a cui i tester sono tornati non per i titoli, ma per come si comportano quando le telecamere si spengono.", es: "Algunos coches llegan con expectativas bajas y se marchan con una admiración tranquila. Son aquellos a los que los probadores volvieron no por el titular, sino por cómo se comportan cuando se apagan las cámaras." } },
  "calm-highway-cruisers": { title: { en: "Calm highway cruisers", no: "Rolige motorveikryssere", de: "Gelassene Autobahn-Cruiser", sv: "Lugna motorvägskryssare", fr: "Les grandes routières sereines", pl: "Spokojni połykacze autostrad", it: "Le autostradali più serene", es: "Grandes ruteros serenos" }, description: { en: "Hours dissolve. The car simply continues.", no: "Timene løser seg opp. Bilen bare fortsetter.", de: "Die Stunden lösen sich auf. Das Auto macht einfach weiter.", sv: "Timmarna löser upp sig. Bilen bara fortsätter.", fr: "Les heures s’effacent. La voiture continue simplement.", pl: "Godziny się rozpuszczają. Samochód po prostu jedzie dalej.", it: "Le ore si sciolgono. L’auto continua semplicemente ad andare.", es: "Las horas se diluyen. El coche simplemente sigue adelante." }, body: { en: "Highway driving rewards refinement: stability at speed, low cabin noise, seats that stay honest after four hours and damping that never turns the journey into work.", no: "Motorveikjøring belønner raffinement: stabilitet i fart, lav kupéstøy, seter som fortsatt føles riktige etter fire timer og demping som aldri gjør turen til arbeid.", de: "Autobahnfahrten belohnen Raffinesse: Stabilität im Tempo, geringe Geräuschkulisse, Sitze mit Langzeit-Qualität und ein Fahrwerk, das die Reise nicht zur Arbeit macht.", sv: "Motorvägskörning belönar förfining: stabilitet i fart, låg kupéstörning, stolar som fortfarande känns rätt efter fyra timmar och dämpning som aldrig gör resan till arbete.", fr: "L’autoroute récompense le raffinement: stabilité à haute vitesse, faible bruit de roulage, sièges honnêtes après quatre heures et amortissement qui ne transforme jamais le trajet en corvée.", pl: "Autostrada wynagradza dopracowanie: stabilność przy prędkości, niski hałas w kabinie, fotele uczciwe po czterech godzinach i tłumienie, które nie zamienia podróży w pracę.", it: "L’autostrada premia la raffinatezza: stabilità alle alte velocità, poco rumore a bordo, sedili ancora onesti dopo quattro ore e sospensioni che non trasformano il viaggio in un compito.", es: "La autopista premia el refinamiento: estabilidad a velocidad, poco ruido en el habitáculo, asientos que siguen siendo honestos tras cuatro horas y una suspensión que nunca convierte el viaje en trabajo." } },
  "winter-confidence": { title: { en: "Winter confidence", no: "Vintertrygghet", de: "Souverän durch den Winter", sv: "Vintertrygghet", fr: "Confiance hivernale", pl: "Pewność zimą", it: "Fiducia in inverno", es: "Confianza invernal" }, description: { en: "AWD, heat pumps, and the temperament of a Nordic engineer.", no: "Firehjulsdrift, varmepumper og temperamentet til en nordisk ingeniør.", de: "Allrad, Wärmepumpen und das Temperament eines nordischen Ingenieurs.", sv: "Fyrhjulsdrift, värmepumpar och temperamentet hos en nordisk ingenjör.", fr: "Transmission intégrale, pompes à chaleur et tempérament d’ingénieur nordique.", pl: "AWD, pompy ciepła i temperament nordyckiego inżyniera.", it: "Trazione integrale, pompe di calore e il temperamento di un ingegnere nordico.", es: "Tracción total, bombas de calor y el temperamento de un ingeniero nórdico." }, body: { en: "Winter rewards quiet competence over headline horsepower. Heat pumps, pre-conditioning, sure-footed AWD and cabins that still hold warmth when the forecast turns serious — these are AutoVere’s most reassuring picks.", no: "Vinteren belønner stille kompetanse mer enn overskriftskrefter. Varmepumper, forvarming, trygg AWD og kupeer som holder på varmen når været blir alvorlig — dette er AutoVeres mest beroligende valg.", de: "Der Winter belohnt stille Kompetenz stärker als Schlagzeilen-PS. Wärmepumpen, Vorkonditionierung, trittsicherer Allrad und Innenräume, die Wärme halten, wenn die Prognose ernst wird — das sind AutoVeres beruhigendste Empfehlungen.", sv: "Vintern belönar tyst kompetens mer än rubrikhästkrafter. Värmepumpar, förkonditionering, trygg AWD och kupéer som håller värmen när prognosen skärps — det här är AutoVeres mest betryggande val.", fr: "L’hiver récompense la compétence tranquille plus que la puissance de façade. Pompes à chaleur, préconditionnement, transmission intégrale sûre et habitacles qui restent chauds quand les prévisions se durcissent — voici les choix les plus rassurants d’AutoVere.", pl: "Zima nagradza cichą kompetencję bardziej niż konie mechaniczne z nagłówków. Pompy ciepła, preconditioning, pewne AWD i kabiny, które zatrzymują ciepło, gdy prognoza robi się poważna — to najbardziej uspokajające wybory AutoVere.", it: "L’inverno premia la competenza silenziosa più della potenza da copertina. Pompe di calore, precondizionamento, AWD sicura e abitacoli che mantengono il calore quando il meteo si fa serio — queste sono le scelte più rassicuranti di AutoVere.", es: "El invierno premia la competencia silenciosa más que los caballos de titular. Bombas de calor, preacondicionamiento, AWD de verdad y habitáculos capaces de conservar el calor cuando la previsión se pone seria: estas son las apuestas más tranquilizadoras de AutoVere." } },
};
